import os
import json
import uuid
import logging
from typing import Any, Dict, Optional

import boto3
from botocore.exceptions import BotoCoreError, ClientError

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class SQSPublisher:
    def __init__(
        self,
        queue_url: str,
        region_name: Optional[str] = None,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        aws_session_token: Optional[str] = None,
    ):
        self.queue_url = queue_url
        session_kwargs = {}
        if region_name:
            session_kwargs["region_name"] = region_name
        if aws_access_key_id:
            session_kwargs["aws_access_key_id"] = aws_access_key_id
        if aws_secret_access_key:
            session_kwargs["aws_secret_access_key"] = aws_secret_access_key
        if aws_session_token:
            session_kwargs["aws_session_token"] = aws_session_token

        self.sqs = boto3.client("sqs", **session_kwargs)

    def publish_user_data(self, user_data: Dict[str, Any]) -> Dict[str, Any]:
        message_id = str(uuid.uuid4())
        payload = {
            "message_id": message_id,
            "type": "user_data",
            "data": user_data,
        }

        try:
            response = self.sqs.send_message(
                QueueUrl=self.queue_url,
                MessageBody=json.dumps(payload, ensure_ascii=False),
                MessageAttributes={
                    "message_type": {
                        "DataType": "String",
                        "StringValue": "user_data",
                    },
                    "contains_pii": {
                        "DataType": "String",
                        "StringValue": "true",
                    },
                },
            )
            logger.info("Published message_id=%s sqs_message_id=%s", message_id, response.get("MessageId"))
            return response
        except (BotoCoreError, ClientError) as exc:
            logger.exception("Failed to publish message_id=%s", message_id)
            raise RuntimeError(f"Failed to send message to SQS: {exc}") from exc


